changeSet.sql:
IF OBJECT_ID('dbo.trg_NodesDeleteCleanup', 'TR') IS NOT NULL
DROP TRIGGER dbo.trg_NodesDeleteCleanup;

EXEC('
    CREATE TRIGGER dbo.trg_NodesDeleteCleanup
    ON dbo.Nodes
    INSTEAD OF DELETE
    AS
    BEGIN
        DELETE FROM dbo.Edges
        WHERE target_node_id IN (SELECT node_id FROM deleted);

        DELETE FROM dbo.Edges
        WHERE source_node_id IN (SELECT node_id FROM deleted);

        DELETE FROM dbo.Nodes
        WHERE node_id IN (SELECT node_id FROM deleted);

        UPDATE g
        SET g.nodes_count = (SELECT COUNT(*) FROM dbo.Nodes n WHERE n.graph_id = g.graph_id)
        FROM dbo.graph g
        WHERE g.graph_id IN (SELECT graph_id FROM deleted);
    END
');
